mapper.select:
select id,
       user_id as userId,
       content_id as contentId,
       content_type as contentType,
       create_time as createTime
from favorite
where user_id = #{userId}
and content_id = #{contentId}
and content_type = #{contentType}
limit 1

mapper.delete:
delete from favorite
where user_id = #{userId}
and content_id = #{contentId}
and content_type = #{contentType}

mapper.select:
select count(*)
from favorite
where content_id = #{contentId}
and content_type = #{contentType}
